INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000023', 'english-specific0', 'culture')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0010-000000000001', 'en', 1, 'partner', 'Thank you for calling Horizon Mobile. My name''s Jake. How can I help you today?', 'Cảm ơn đã gọi đến Horizon Mobile. Tôi là Jake. Tôi có thể giúp gì cho bạn hôm nay?'),
  ('00000000-0000-0000-0010-000000000001', 'en', 2, 'user', 'Hi Jake. I''m calling about a billing issue — I''ve been charged twice for this month''s plan.', 'Xin chào Jake. Tôi gọi về vấn đề thanh toán — tôi bị tính tiền hai lần cho gói tháng này.'),
  ('00000000-0000-0000-0010-000000000001', 'en', 3, 'partner', 'I''m sorry about that. Could I take your account number to pull up your details?', 'Tôi xin lỗi về điều đó. Tôi có thể lấy số tài khoản của bạn để tra thông tin không?'),
  ('00000000-0000-0000-0010-000000000001', 'en', 4, 'user', 'Sure, it''s seven-seven-four-two-dash-nine-eight-six.', 'Được, là 7742-986.'),
  ('00000000-0000-0000-0010-000000000001', 'en', 5, 'partner', 'Bear with me a moment… I''m going to need to put you on a brief hold while I check this.', 'Chờ tôi một chút... Tôi sẽ cần để bạn giữ máy trong khi tôi kiểm tra.'),
  ('00000000-0000-0000-0010-000000000001', 'en', 6, 'user', 'No problem. I''ll hold.', 'Không sao. Tôi sẽ giữ máy.'),
  ('00000000-0000-0000-0010-000000000001', 'en', 7, 'partner', 'Thanks for waiting. I can see the double charge — I''m going to transfer you to our billing team to process the refund.', 'Cảm ơn đã chờ. Tôi thấy khoản thu hai lần — tôi sẽ chuyển bạn đến nhóm thanh toán để xử lý hoàn tiền.'),
  ('00000000-0000-0000-0010-000000000001', 'en', 8, 'user', 'Before you transfer me — can you give me a reference number in case I get disconnected?', 'Trước khi chuyển — bạn có thể cho tôi số tham chiếu không phòng khi mất kết nối?'),
  ('00000000-0000-0000-0010-000000000001', 'en', 9, 'partner', 'Of course. Your reference is HM-dash-seven-four-two-one. Hold the line and I''ll transfer you now.', 'Tất nhiên. Số tham chiếu là HM-7421. Giữ máy và tôi sẽ chuyển ngay.'),
  ('00000000-0000-0000-0010-000000000001', 'en', 10, 'partner', 'Billing team, this is Priya. I understand you have a duplicate charge?', 'Nhóm thanh toán, tôi là Priya. Tôi hiểu bạn bị tính tiền trùng?'),
  ('00000000-0000-0000-0010-000000000001', 'en', 11, 'user', 'That''s right. Reference HM-7421. I''d like to confirm the refund amount and timeline before we finish.', 'Đúng vậy. Số tham chiếu HM-7421. Tôi muốn xác nhận số tiền hoàn lại và thời gian trước khi kết thúc.'),
  ('00000000-0000-0000-0010-000000000001', 'en', 12, 'partner', 'Of course. The duplicate charge of thirty-nine ninety-nine will be refunded within three to five business days.', 'Tất nhiên. Khoản thu trùng 39,99 sẽ được hoàn trong 3–5 ngày làm việc.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0010-000000000002', 'ja', 1, 'partner', 'ホライズン・モバイルにお電話いただきありがとうございます。ジェイクと申します。本日はどのようなご用件でしょうか？', 'Cảm ơn đã gọi đến Horizon Mobile. Tôi là Jake. Hôm nay tôi có thể giúp gì cho bạn?', 'ホライズン・モバイルにおでんわいただきありがとうございます。ジェイクともうします。ほんじつはどのようなごようけんでしょうか？', 'Horaizun Mobairu ni o-denwa itadaki arigatō gozaimasu. Jeiku to mōshimasu. Honjitsu wa dono yō na go-yōken deshō ka?'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 2, 'user', 'こんにちは、ジェイクさん。請求に関してご連絡しました。今月のプランが2回請求されているようです。', 'Xin chào Jake. Tôi liên hệ về vấn đề thanh toán. Có vẻ tôi bị tính tiền hai lần cho gói tháng này.', 'こんにちは、ジェイクさん。せいきゅうにかんしてごれんらくしました。こんげつのプランがにかいせいきゅうされているようです。', 'Konnichiwa, Jeiku-san. Seikyū ni kanshite go-renraku shimashita. Kongetsu no puran ga ni-kai seikyū sarete iru yō desu.'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 3, 'partner', 'ご不便をおかけして申し訳ございません。口座番号をお教えいただけますか？', 'Xin lỗi vì sự bất tiện. Bạn có thể cho tôi số tài khoản không?', 'ごふべんをおかけしてもうしわけございません。こうざばんごうをおしえていただけますか？', 'Go-fuben wo o-kake shite mōshiwake gozaimasen. Kōza-bangō wo oshiete itadakemasu ka?'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 4, 'user', 'はい。7742-986です。', 'Vâng. Là 7742-986.', 'はい。ななよんよんにのきゅうはちろくです。', 'Hai. Nana-yon-yon-ni no kyū-hachi-roku desu.'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 5, 'partner', '少しお待ちください…確認のため、しばらく保留させていただきます。', 'Chờ tôi một chút... Tôi sẽ để bạn giữ máy trong khi kiểm tra.', 'すこしおまちください…かくにんのため、しばらくほりゅうさせていただきます。', 'Sukoshi o-machi kudasai... Kakunin no tame, shibaraku horyū sasete itadakimasu.'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 6, 'user', 'はい、お待ちします。', 'Vâng, tôi sẽ chờ.', 'はい、おまちします。', 'Hai, o-machi shimasu.'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 7, 'partner', 'お待たせいたしました。二重請求を確認できました。返金処理のため、請求チームに転送させていただきます。', 'Cảm ơn đã chờ. Tôi xác nhận khoản thu hai lần. Sẽ chuyển bạn đến nhóm thanh toán để xử lý hoàn tiền.', 'おまたせいたしました。にじゅうせいきゅうをかくにんできました。へんきんしょりのため、せいきゅうチームにてんそうさせていただきます。', 'O-matase itashimashita. Nijū seikyū wo kakunin dekimashita. Henkin shori no tame, seikyū chīmu ni tensō sasete itadakimasu.'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 8, 'user', '転送の前に、電話が切れた場合に備えて参照番号を教えていただけますか？', 'Trước khi chuyển máy, bạn có thể cho tôi số tham chiếu phòng khi bị ngắt không?', 'てんそうのまえに、でんわがきれたばあいにそなえてさんしょうばんごうをおしえていただけますか？', 'Tensō no mae ni, denwa ga kireta baai ni sonaete sanshō-bangō wo oshiete itadakemasu ka?'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 9, 'partner', 'もちろんです。参照番号はHM-7421です。そのままお待ちください、転送いたします。', 'Tất nhiên. Số tham chiếu là HM-7421. Giữ máy, tôi sẽ chuyển ngay.', 'もちろんです。さんしょうばんごうはHM-7421です。そのままおまちください、てんそういたします。', 'Mochiron desu. Sanshō-bangō wa HM-nana-yon-ni-ichi desu. Sono mama o-machi kudasai, tensō itashimasu.'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 10, 'partner', '請求チームのプリヤと申します。二重請求のご件でしょうか？', 'Nhóm thanh toán, tôi là Priya. Bạn gọi về khoản thu trùng phải không?', 'せいきゅうチームのプリヤともうします。にじゅうせいきゅうのごけんでしょうか？', 'Seikyū chīmu no Puriya to mōshimasu. Nijū seikyū no go-ken deshō ka?'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 11, 'user', 'そうです。参照番号はHM-7421です。終わる前に、返金額と期間を確認させていただけますか？', 'Đúng vậy. Số tham chiếu HM-7421. Trước khi kết thúc, tôi muốn xác nhận số tiền và thời gian hoàn.', 'そうです。さんしょうばんごうはHM-7421です。おわるまえに、へんきんがくとじかんをかくにんさせていただけますか？', 'Sō desu. Sanshō-bangō wa HM-nana-yon-ni-ichi desu. Owaru mae ni, henkin-gaku to jikan wo kakunin sasete itadakemasu ka?'),
  ('00000000-0000-0000-0010-000000000002', 'ja', 12, 'partner', 'はい。39.99ドルの二重請求は、3〜5営業日以内に返金いたします。', 'Vâng. Khoản thu trùng 39,99 đô sẽ được hoàn trong 3–5 ngày làm việc.', 'はい。さんじゅうきゅうてんきゅうきゅうドルのにじゅうせいきゅうは、さんからごえいぎょうびいないにへんきんいたします。', 'Hai. Sanjū-kyū-ten-kyū-kyū doru no nijū seikyū wa, san kara go eigyō-bi inai ni henkin itashimasu.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000024', 'english-specific1', 'culture')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0010-000000000003', 'en', 1, 'partner', 'I just posted a photo of my hike. What kind of caption do you think works well?', 'Tôi vừa đăng ảnh đi bộ leo núi. Bạn nghĩ loại chú thích nào hiệu quả?'),
  ('00000000-0000-0000-0010-000000000003', 'en', 2, 'user', 'Something short and punchy works best — like ''Legs aching, heart full'' or ''Peak happiness up here.''', 'Ngắn gọn và ấn tượng là tốt nhất — như ''Chân đau, lòng no'' hoặc ''Hạnh phúc đỉnh cao ở đây.'''),
  ('00000000-0000-0000-0010-000000000003', 'en', 3, 'partner', 'Oh I like that. What about hashtags — should I add a lot?', 'Ồ tôi thích vậy. Còn hashtag — tôi có nên thêm nhiều không?'),
  ('00000000-0000-0000-0010-000000000003', 'en', 4, 'user', 'Three to five targeted ones is usually better than twenty generic ones. Like #hikinglife, #weekendescape.', 'Ba đến năm hashtag phù hợp thường tốt hơn hai mươi cái chung chung. Như #hikinglife, #weekendescape.'),
  ('00000000-0000-0000-0010-000000000003', 'en', 5, 'partner', 'Got it. Now someone commented ''This is giving me wanderlust!'' — what does that mean?', 'Hiểu rồi. Bây giờ có người bình luận ''This is giving me wanderlust!'' — điều đó có nghĩa gì?'),
  ('00000000-0000-0000-0010-000000000003', 'en', 6, 'user', 'It means your photo is making them want to travel. ''Giving me X'' is a super trendy phrase right now.', 'Nghĩa là ảnh của bạn khiến họ muốn đi du lịch. ''Giving me X'' là cụm từ rất thịnh hành hiện nay.'),
  ('00000000-0000-0000-0010-000000000003', 'en', 7, 'partner', 'What''s a good reply to that?', 'Phản hồi tốt cho điều đó là gì?'),
  ('00000000-0000-0000-0010-000000000003', 'en', 8, 'user', 'Something like ''Come with me next time!'' or ''The trail is calling your name!'' — keep it warm and inviting.', 'Điều gì đó như ''Lần sau cùng đi với tôi nhé!'' hoặc ''Con đường đang gọi tên bạn!'' — giữ nó ấm áp và mời gọi.'),
  ('00000000-0000-0000-0010-000000000003', 'en', 9, 'partner', 'And someone said ''no cap this looks amazing'' — what''s ''no cap''?', 'Và ai đó nói ''no cap this looks amazing'' — ''no cap'' nghĩa là gì?'),
  ('00000000-0000-0000-0010-000000000003', 'en', 10, 'user', '''No cap'' means ''no lie'' or ''for real''. So they''re saying it genuinely looks amazing — not sarcastically.', '''No cap'' nghĩa là ''thật đấy'' hoặc ''thực sự''. Vậy họ đang nói nó thật sự trông tuyệt vời — không mỉa mai.'),
  ('00000000-0000-0000-0010-000000000003', 'en', 11, 'partner', 'Okay! I think I need to learn more of this internet English.', 'Ồ! Tôi nghĩ tôi cần học thêm tiếng Anh internet này.'),
  ('00000000-0000-0000-0010-000000000003', 'en', 12, 'user', 'It changes fast! But the basics — short, positive, personal — stay the same. Just write how you actually feel.', 'Nó thay đổi nhanh lắm! Nhưng những điều cơ bản — ngắn, tích cực, cá nhân — vẫn giống nhau. Chỉ cần viết những gì bạn thực sự cảm thấy.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0010-000000000004', 'ja', 1, 'partner', 'ハイキングの写真を投稿しました。どんなキャプションがいいと思いますか？', 'Tôi vừa đăng ảnh đi bộ. Bạn nghĩ loại chú thích nào hay?', 'ハイキングのしゃしんをとうこうしました。どんなキャプションがいいとおもいますか？', 'Haikingu no shashin wo tōkō shimashita. Donna kyapushon ga ii to omoimasu ka?'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 2, 'user', '短くてインパクトのあるものがベストです。たとえば「Legs aching, heart full」や「Peak happiness up here」など。', 'Ngắn gọn và ấn tượng là tốt nhất. Ví dụ như ''Legs aching, heart full'' hay ''Peak happiness up here''.', 'みじかくてインパクトのあるものがベストです。たとえば「Legs aching, heart full」や「Peak happiness up here」など。', 'Mijikakute inpakuto no aru mono ga besuto desu. Tatoeba ''Legs aching, heart full'' ya ''Peak happiness up here'' nado.'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 3, 'partner', 'いいですね。ハッシュタグはたくさんつけた方がいいですか？', 'Hay đó. Nên thêm nhiều hashtag không?', 'いいですね。ハッシュタグはたくさんつけたほうがいいですか？', 'Ii desu ne. Hasshu tagu wa takusan tsuketa hō ga ii desu ka?'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 4, 'user', '一般的なものを20個つけるより、関連性の高いものを3〜5個にする方が効果的です。#hikinglife や #weekendescape などですね。', 'Thêm 20 cái chung chung không bằng 3–5 cái phù hợp. Như #hikinglife hay #weekendescape.', 'いっぱんてきなものをにじゅっこつけるより、かんれんせいのたかいものをさんからごこにするほうがこうかてきです。ハイキングライフやウィークエンドエスケープなどですね。', 'Ippanteki na mono wo nijukko tsukeru yori, kanrensei no takai mono wo san kara go-ko ni suru hō ga kōkateki desu. #hikinglife ya #weekendescape nado desu ne.'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 5, 'partner', 'わかりました。ところで、「This is giving me wanderlust!」ってコメントが来たんですけど、どういう意味ですか？', 'Hiểu rồi. Có người bình luận ''This is giving me wanderlust!'' — nghĩa là gì vậy?', 'わかりました。ところで、「This is giving me wanderlust!」ってコメントがきたんですけど、どういういみですか？', 'Wakarimashita. Tokoro de, ''This is giving me wanderlust!'' tte komento ga kita n desu kedo, dō iu imi desu ka?'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 6, 'user', 'その写真を見て旅に出たくなったということです。「Giving me X」は今すごく流行っている表現ですよ。', 'Nghĩa là xem ảnh đó họ muốn đi du lịch. ''Giving me X'' là cụm từ rất thịnh hành hiện nay.', 'そのしゃしんをみてたびにでたくなったということです。「Giving me X」はいますごくはやっているひょうげんですよ。', 'Sono shashin wo mite tabi ni detaku natta to iu koto desu. ''Giving me X'' wa ima sugoku hayatte iru hyōgen desu yo.'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 7, 'partner', 'それにどう返信すればいいですか？', 'Nên phản hồi lại thế nào?', 'それにどうへんしんすればいいですか？', 'Sore ni dō henshin sureba ii desu ka?'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 8, 'user', '「Come with me next time!」や「The trail is calling your name!」など、温かく誘うような返し方がいいですよ。', 'Như ''Come with me next time!'' hay ''The trail is calling your name!'' — kiểu ấm áp và mời gọi là tốt.', '「Come with me next time!」や「The trail is calling your name!」など、あたたかくさそうようなかえしかたがいいですよ。', '''Come with me next time!'' ya ''The trail is calling your name!'' nado, atatakaku sasō yō na kaeshi-kata ga ii desu yo.'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 9, 'partner', '「no cap this looks amazing」っていうコメントも来たんですけど、「no cap」って何ですか？', 'Còn có người nói ''no cap this looks amazing'' — ''no cap'' là gì vậy?', '「no cap this looks amazing」っていうコメントもきたんですけど、「no cap」ってなんですか？', '''No cap this looks amazing'' tte iu komento mo kita n desu kedo, ''no cap'' tte nan desu ka?'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 10, 'user', '「No cap」は「嘘じゃなくて」「本当に」という意味です。つまり、本当にすごいと思っていると言っているんです。皮肉じゃないですよ。', '''No cap'' nghĩa là ''thật đấy'' hoặc ''thực sự''. Tức là họ thực sự nghĩ nó tuyệt vời — không mỉa mai.', '「No cap」は「うそじゃなくて」「ほんとうに」というみです。つまり、ほんとうにすごいとおもっていると言っているんです。ひにくじゃないですよ。', '''No cap'' wa ''uso ja nakute'' ''hontō ni'' to iu imi desu. Tsumari, hontō ni sugoi to omotte iru to itte iru n desu. Hiniku ja nai desu yo.'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 11, 'partner', 'なるほど！インターネット英語、もっと勉強しないといけませんね。', 'Ra vậy! Có lẽ tôi cần học thêm tiếng Anh internet.', 'なるほど！インターネットえいご、もっとべんきょうしないといけませんね。', 'Naruhodo! Intānetto Eigo, motto benkyō shinai to ikemasen ne.'),
  ('00000000-0000-0000-0010-000000000004', 'ja', 12, 'user', '変化が早いですが、基本は同じです。短く、前向きに、自分らしく書く。感じたままを書けば大丈夫ですよ。', 'Thay đổi nhanh lắm, nhưng cơ bản vẫn giống nhau. Ngắn, tích cực, cá nhân. Cứ viết những gì bạn cảm thấy thôi.', 'へんかがはやいですが、きほんはおなじです。みじかく、まえむきに、じぶんらしくかく。かんじたままをかけばだいじょうぶですよ。', 'Henka ga hayai desu ga, kihon wa onaji desu. Mijikaku, mae-muki ni, jibunrashiku kaku. Kanjita mama wo kakeba daijōbu desu yo.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000025', 'english-specific2', 'culture')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0010-000000000005', 'en', 1, 'partner', 'Have you seen anything good recently?', 'Gần đây bạn có xem gì hay không?'),
  ('00000000-0000-0000-0010-000000000005', 'en', 2, 'user', 'Yes! I finally watched Past Lives — have you seen it? It completely wrecked me.', 'Có! Tôi vừa xem Past Lives — bạn xem chưa? Nó làm tôi xúc động hoàn toàn.'),
  ('00000000-0000-0000-0010-000000000005', 'en', 3, 'partner', 'I have! I cried at the end. What did you think of the ending?', 'Tôi xem rồi! Tôi khóc ở cuối phim. Bạn nghĩ gì về phần kết?'),
  ('00000000-0000-0000-0010-000000000005', 'en', 4, 'user', 'I thought it was perfect — bittersweet but hopeful. It didn''t try to wrap everything up neatly.', 'Tôi nghĩ nó hoàn hảo — đắng cay nhưng đầy hy vọng. Nó không cố gắng gói gọn mọi thứ.'),
  ('00000000-0000-0000-0010-000000000005', 'en', 5, 'partner', 'Agreed. The music was beautiful too. Are you into film soundtracks generally?', 'Đồng ý. Nhạc phim cũng rất đẹp. Bạn có thích nhạc phim nói chung không?'),
  ('00000000-0000-0000-0010-000000000005', 'en', 6, 'user', 'Definitely — I''ve been obsessed with the Oppenheimer score lately. Ludwig Göransson is incredible.', 'Chắc chắn rồi — tôi đang mê nhạc phim Oppenheimer dạo này. Ludwig Göransson thật xuất sắc.'),
  ('00000000-0000-0000-0010-000000000005', 'en', 7, 'partner', 'Yes! His stuff is so atmospheric. Do you listen to much non-film music?', 'Đúng vậy! Âm nhạc của anh ấy rất gợi không khí. Bạn có nghe nhiều nhạc ngoài phim không?'),
  ('00000000-0000-0000-0010-000000000005', 'en', 8, 'user', 'A lot of indie and jazz. Right now I''m really into this Japanese jazz pianist — Hiromi Uehara.', 'Nhiều indie và jazz. Hiện tại tôi đang rất thích nghệ sĩ piano jazz Nhật Bản này — Hiromi Uehara.'),
  ('00000000-0000-0000-0010-000000000005', 'en', 9, 'partner', 'Oh I don''t know her. Is she on Spotify?', 'Ồ tôi không biết cô ấy. Cô ấy có trên Spotify không?'),
  ('00000000-0000-0000-0010-000000000005', 'en', 10, 'user', 'She is! Start with ''Place to Be'' — it''s upbeat and a bit funky. I think you''d love it.', 'Có! Bắt đầu với ''Place to Be'' — nó sôi động và hơi funky. Tôi nghĩ bạn sẽ thích.'),
  ('00000000-0000-0000-0010-000000000005', 'en', 11, 'partner', 'I''ll check it out. Do you have a favourite genre overall?', 'Tôi sẽ thử nghe. Bạn có thể loại nhạc yêu thích nhất không?'),
  ('00000000-0000-0000-0010-000000000005', 'en', 12, 'user', 'Honestly it changes with my mood. But if I had to pick one — jazz. It never gets old for me.', 'Thành thật mà nói thì thay đổi theo tâm trạng. Nhưng nếu phải chọn một — jazz. Với tôi nó không bao giờ nhàm.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0010-000000000006', 'ja', 1, 'partner', '最近、何か面白いもの見ましたか？', 'Gần đây bạn có xem gì hay không?', 'さいきん、なにかおもしろいものみましたか？', 'Saikin, nani ka omoshiroi mono mimashita ka?'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 2, 'user', 'はい！「Past Lives」をやっと観ました。観ましたか？すごく感動しました。', 'Có! Tôi vừa xem ''Past Lives''. Bạn xem chưa? Tôi xúc động lắm.', 'はい！「Past Lives」をやっとみました。みましたか？すごくかんどうしました。', 'Hai! ''Past Lives'' wo yatto mimashita. Mimashita ka? Sugoku kandō shimashita.'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 3, 'partner', '観ましたよ！最後は泣きました。結末についてどう思いましたか？', 'Tôi xem rồi! Tôi khóc ở phần kết. Bạn nghĩ gì về kết phim?', 'みましたよ！さいごはなきました。けつまつについてどうおもいましたか？', 'Mimashita yo! Saigo wa nakimashita. Ketsumatu ni tsuite dō omoimashita ka?'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 4, 'user', '完璧だと思いました。切ないけど希望を感じる終わり方で、無理に綺麗にまとめていないのがよかったです。', 'Tôi nghĩ nó hoàn hảo. Kết thúc đắng cay nhưng đầy hy vọng, không cố gắng gói gọn mọi thứ.', 'かんぺきだとおもいました。せつないけどきぼうをかんじるおわりかたで、むりにきれいにまとめていないのがよかったです。', 'Kanpeki da to omoimashita. Setsunai kedo kibō wo kanjiru owari-kata de, muri ni kirei ni matomete inai no ga yokatta desu.'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 5, 'partner', '同感です。音楽も素晴らしかった。映画のサウンドトラックが好きですか？', 'Đồng ý. Nhạc phim cũng đẹp. Bạn có thích nhạc phim không?', 'どうかんです。おんがくもすばらしかった。えいがのサウンドトラックがすきですか？', 'Dōkan desu. Ongaku mo subarashikatta. Eiga no saundotorakku ga suki desu ka?'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 6, 'user', 'はい！最近「オッペンハイマー」のサウンドトラックにはまっています。ルードヴィヒ・ゴランソンは本当に素晴らしいです。', 'Có! Tôi đang mê nhạc phim Oppenheimer dạo này. Ludwig Göransson thật xuất sắc.', 'はい！さいきん「オッペンハイマー」のサウンドトラックにはまっています。ルードヴィヒ・ゴランソンはほんとうにすばらしいです。', 'Hai! Saikin ''Oppenheimer'' no saundotorakku ni hamatte imasu. Rūdovihi Goranson wa hontō ni subarashii desu.'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 7, 'partner', 'そうですよね！雰囲気が出ますよね。映画以外の音楽はよく聴きますか？', 'Đúng vậy! Rất gợi không khí. Bạn có nghe nhiều nhạc ngoài phim không?', 'そうですよね！ふんいきがでますよね。えいがいがいのおんがくはよくきますか？', 'Sō desu yo ne! Fun''iki ga demasu yo ne. Eiga igai no ongaku wa yoku kikimasu ka?'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 8, 'user', 'インディーズとジャズをよく聴きます。今は上原ひろみさんにはまっています。', 'Tôi nghe nhiều indie và jazz. Hiện tôi đang rất thích Hiromi Uehara.', 'インディーズとジャズをよくきます。いまはうえはらひろみさんにはまっています。', 'Indīzu to jazu wo yoku kikimasu. Ima wa Uehara Hiromi-san ni hamatte imasu.'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 9, 'partner', '知りませんでした。Spotifyにありますか？', 'Tôi chưa biết cô ấy. Có trên Spotify không?', 'しりませんでした。Spotifyにありますか？', 'Shirimasen deshita. Spotify ni arimasu ka?'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 10, 'user', 'あります！まず「Place to Be」から聴いてみてください。明るくてファンキーな曲です。きっと気に入ると思います。', 'Có! Hãy thử nghe ''Place to Be'' trước. Nó sôi động và hơi funky. Tôi nghĩ bạn sẽ thích.', 'あります！まず「Place to Be」からきいてみてください。あかるくてファンキーなきょくです。きっときにいるとおもいます。', 'Arimasu! Mazu ''Place to Be'' kara kiite mite kudasai. Akarukute fankī na kyoku desu. Kitto ki ni iru to omoimasu.'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 11, 'partner', '聴いてみます！全体的に一番好きなジャンルはありますか？', 'Tôi sẽ thử nghe! Nhìn chung bạn thích thể loại nào nhất?', 'きいてみます！ぜんたいてきにいちばんすきなジャンルはありますか？', 'Kiite mimasu! Zentaiteki ni ichiban suki na janru wa arimasu ka?'),
  ('00000000-0000-0000-0010-000000000006', 'ja', 12, 'user', '正直、気分によって変わりますね。でも一つ選ぶなら——ジャズです。私には決して飽きないジャンルです。', 'Thành thật mà nói thì thay đổi theo tâm trạng. Nhưng nếu chọn một — jazz. Với tôi nó không bao giờ nhàm.', 'しょうじき、きぶんによってかわりますね。でもひとつえらぶなら——ジャズです。わたしにはけっしてあきないジャンルです。', 'Shōjiki, kibun ni yotte kawarimasu ne. Demo hitotsu erabu nara — jazu desu. Watashi ni wa kesshite akinai janru desu.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000026', 'english-specific3', 'culture')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0010-000000000007', 'en', 1, 'partner', 'Tell me about a time you had to manage a difficult situation with a tight deadline.', 'Hãy kể về một lần bạn phải xử lý tình huống khó khăn với thời hạn gấp.'),
  ('00000000-0000-0000-0010-000000000007', 'en', 2, 'user', 'Sure. Last year, our main supplier cancelled two days before a product launch. [Situation]', 'Được. Năm ngoái, nhà cung cấp chính của chúng tôi huỷ hợp đồng hai ngày trước khi ra mắt sản phẩm. [Tình huống]'),
  ('00000000-0000-0000-0010-000000000007', 'en', 3, 'partner', 'That sounds stressful. What was your role in that situation?', 'Nghe có vẻ căng thẳng. Vai trò của bạn trong tình huống đó là gì?'),
  ('00000000-0000-0000-0010-000000000007', 'en', 4, 'user', 'I was the project lead, so it fell on me to find a solution without delaying the launch. [Task]', 'Tôi là trưởng dự án, nên trách nhiệm tìm giải pháp mà không trì hoãn ra mắt nằm ở tôi. [Nhiệm vụ]'),
  ('00000000-0000-0000-0010-000000000007', 'en', 5, 'partner', 'What steps did you take?', 'Bạn đã thực hiện những bước gì?'),
  ('00000000-0000-0000-0010-000000000007', 'en', 6, 'user', 'First, I contacted three backup suppliers we''d previously vetted. Two could meet the timeline. I negotiated an emergency order with the faster one overnight. [Action]', 'Đầu tiên, tôi liên hệ ba nhà cung cấp dự phòng mà chúng tôi đã kiểm duyệt trước. Hai người có thể đáp ứng thời hạn. Tôi đàm phán đơn hàng khẩn cấp với nhà cung cấp nhanh hơn trong đêm. [Hành động]'),
  ('00000000-0000-0000-0010-000000000007', 'en', 7, 'partner', 'Were there any obstacles along the way?', 'Có trở ngại nào trên đường không?'),
  ('00000000-0000-0000-0010-000000000007', 'en', 8, 'user', 'Yes — the backup supplier''s pricing was fifteen percent higher. I had to get rapid approval from finance and restructure one part of the budget.', 'Có — giá của nhà cung cấp dự phòng cao hơn 15%. Tôi phải nhanh chóng xin phê duyệt từ tài chính và tái cơ cấu một phần ngân sách.'),
  ('00000000-0000-0000-0010-000000000007', 'en', 9, 'partner', 'And what was the outcome?', 'Và kết quả là gì?'),
  ('00000000-0000-0000-0010-000000000007', 'en', 10, 'user', 'The launch went ahead on schedule. We absorbed the cost difference and actually exceeded our first-week sales target by twelve percent. [Result]', 'Ra mắt diễn ra đúng kế hoạch. Chúng tôi hấp thụ chênh lệch chi phí và thực sự vượt chỉ tiêu bán hàng tuần đầu 12%. [Kết quả]'),
  ('00000000-0000-0000-0010-000000000007', 'en', 11, 'partner', 'Impressive. What did you learn from that experience?', 'Ấn tượng. Bạn học được gì từ kinh nghiệm đó?'),
  ('00000000-0000-0000-0010-000000000007', 'en', 12, 'user', 'I learned the value of pre-approved backup suppliers — and that staying calm and methodical under pressure is often more effective than moving fast and chaotically.', 'Tôi học được giá trị của nhà cung cấp dự phòng đã được phê duyệt trước — và rằng bình tĩnh và có phương pháp dưới áp lực thường hiệu quả hơn là di chuyển nhanh mà hỗn loạn.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0010-000000000008', 'ja', 1, 'partner', '締め切りが迫る中で難しい状況を乗り越えた経験を教えてください。', 'Hãy kể về một lần bạn vượt qua tình huống khó khăn khi thời hạn gấp.', 'しめきりがせまるなかでむずかしいじょうきょうをのりこえたけいけんをおしえてください。', 'Shimekiri ga semaru naka de muzukashii jōkyō wo norikoe ta keiken wo oshiete kudasai.'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 2, 'user', 'はい。昨年、製品発売の2日前にメインのサプライヤーが契約をキャンセルしました。【状況】', 'Vâng. Năm ngoái, nhà cung cấp chính huỷ hợp đồng 2 ngày trước khi ra mắt sản phẩm. [Tình huống]', 'はい。さくねん、せいひんはつばいのふつかまえにメインのサプライヤーがけいやくをキャンセルしました。', 'Hai. Sakunen, seihin hatsubai no futsuka mae ni mein no sapuraiyā ga keiyaku wo kyanseru shimashita.'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 3, 'partner', 'それはストレスだったでしょうね。その状況でのあなたの役割は何でしたか？', 'Chắc căng thẳng lắm. Vai trò của bạn trong tình huống đó là gì?', 'それはストレスだったでしょうね。そのじょうきょうでのあなたのやくわりはなんでしたか？', 'Sore wa sutoresu datta deshō ne. Sono jōkyō de no anata no yakuwari wa nan deshita ka?'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 4, 'user', '私がプロジェクトリードでしたので、発売を遅らせずに解決策を見つける責任が私にありました。【課題】', 'Tôi là trưởng dự án, nên trách nhiệm tìm giải pháp mà không trì hoãn ra mắt nằm ở tôi. [Nhiệm vụ]', 'わたしがプロジェクトリードでしたので、はつばいをおくらせずにかいけつさくをみつけるせきにんがわたしにありました。', 'Watashi ga purojekuto rīdo deshita node, hatsubai wo okurase zu ni kaiketsu-saku wo mitsukeru sekinin ga watashi ni arimashita.'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 5, 'partner', 'どのような手順を踏みましたか？', 'Bạn đã thực hiện những bước gì?', 'どのようなてじゅんをふみましたか？', 'Dono yō na tejun wo fumimashita ka?'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 6, 'user', 'まず、事前に審査していたバックアップサプライヤー3社に連絡しました。そのうち2社が納期を満たせるとのことで、より早い方と夜通し緊急発注の交渉をしました。【行動】', 'Đầu tiên liên hệ 3 nhà cung cấp dự phòng đã kiểm duyệt. Hai người đáp ứng được thời hạn, tôi đàm phán đơn hàng khẩn cấp với nhà nhanh hơn trong đêm. [Hành động]', 'まず、じぜんにしんさしていたバックアップサプライヤーさんしゃにれんらくしました。そのうちにしゃがのうきをみたせるとのことで、よりはやいほうとよとおしきんきゅうはっちゅうのこうしょうをしました。', 'Mazu, jizen ni shinsa shite ita bakkuappu sapuraiyā san-sha ni renraku shimashita. Sono uchi ni-sha ga nōki wo mitaseru to no koto de, yori hayai hō to yodōshi kinkyū hatchū no kōshō wo shimashita.'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 7, 'partner', '途中で困難はありましたか？', 'Có trở ngại nào trên đường không?', 'とちゅうでこんなんはありましたか？', 'Tochū de konnan wa arimashita ka?'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 8, 'user', 'はい。バックアップ先の価格が15%高かったので、財務部門から迅速な承認を得て予算の一部を組み直す必要がありました。', 'Có. Giá nhà cung cấp dự phòng cao hơn 15%, nên tôi phải nhanh chóng xin phê duyệt từ tài chính và tái cơ cấu một phần ngân sách.', 'はい。バックアップさきのかかくがじゅうごぱーせんとたかかったので、ざいむぶもんからじんそくなしょうにんをえてよさんのいちぶをくみなおすひつようがありました。', 'Hai. Bakkuappu-saki no kakaku ga jūgo-pāsento takakatta node, zaimu-bumon kara jinsoku na shōnin wo ete yosan no ichi-bu wo kuminaōsu hitsuyō ga arimashita.'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 9, 'partner', '結果はどうなりましたか？', 'Kết quả là gì?', 'けっかはどうなりましたか？', 'Kekka wa dō narimashita ka?'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 10, 'user', '予定通り発売できました。コスト差は吸収し、初週の販売目標を12%超えることができました。【結果】', 'Ra mắt đúng kế hoạch. Hấp thụ chênh lệch chi phí và vượt chỉ tiêu bán hàng tuần đầu 12%. [Kết quả]', 'よていどおりはつばいできました。コストさはきゅうしゅうし、しょしゅうのはんばいもくひょうをじゅうにぱーせんとこえることができました。', 'Yotei dōri hatsubai dekimashita. Kosuto-sa wa kyūshū shi, shoshu no hanbai mokuhyō wo jūni-pāsento koeru koto ga dekimashita.'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 11, 'partner', '素晴らしいですね。その経験から何を学びましたか？', 'Ấn tượng. Bạn học được gì từ kinh nghiệm đó?', 'すばらしいですね。そのけいけんからなにをまなびましたか？', 'Subarashii desu ne. Sono keiken kara nani wo manabimashita ka?'),
  ('00000000-0000-0000-0010-000000000008', 'ja', 12, 'user', '事前承認済みのバックアップサプライヤーを用意しておくことの重要性を学びました。また、プレッシャー下では焦って混乱するよりも、冷静かつ体系的に動く方が効果的だということも実感しました。', 'Tôi học được tầm quan trọng của nhà cung cấp dự phòng đã được phê duyệt trước. Và rằng bình tĩnh, có hệ thống dưới áp lực thường hiệu quả hơn là vội vã hỗn loạn.', 'じぜんしょうにんずみのバックアップサプライヤーをようしておくことのじゅうようせいをまなびました。また、プレッシャーかではあせってこんらんするよりも、れいせいかつたいけいてきにうごくほうがこうかてきだということもじっかんしました。', 'Jizen shōnin-zumi no bakkuappu sapuraiyā wo yōi shite oku koto no jūyōsei wo manabimashita. Mata, puressshā ka de wa asette konran suru yori mo, reisei katsu taikeiteki ni ugoku hō ga kōkateki da to iu koto mo jikkan shimashita.');
